import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { UpdateWorkStatusParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/UpdateWorkStatusParser';

export class UpdateWorkStatusEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: Function) {
        super(callback, UpdateWorkStatusParser);
    }

    public getParser(): UpdateWorkStatusParser {
        return this.parser as UpdateWorkStatusParser;
    }
}
